const { execSync } = require('child_process');
// No required input for listing apps
try {
  const cmd = 'argocd app list -o json --server host.docker.internal:8080 --insecure';
  const stdout = execSync(cmd, { encoding: 'utf8', timeout: 30000 });
  // Optional: simplify the json output if it's too large, but LLM usually handles it
  return [{ json: { stdout: stdout || '[]', stderr: '' } }];
} catch(e) {
  return [{ json: { stdout: e.stdout || '', stderr: e.stderr || e.message } }];
}
